mapper.select:
SELECT id, conversation_id, sender_id, content_type, content,
       file_url, file_name, file_size, send_time
FROM chat_message WHERE id = #{id}

SELECT * FROM (
    SELECT id, conversation_id, sender_id, content_type, content,
           file_url, file_name, file_size, send_time
    FROM chat_message
    WHERE conversation_id = #{conversationId}

        AND id < #{cursor}

    ORDER BY id DESC
    LIMIT #{limit}
) t ORDER BY t.id ASC
